import{_ as e,c as o,o as l,a4 as i}from"./chunks/framework.DqmDFLd5.js";const m=JSON.parse('{"title":"关于 PR (Pull Request)","description":"","frontmatter":{"title":"关于 PR (Pull Request)","prev":{"text":"关于补全的 json 文件结构","link":"../completion/index.md"}},"headers":[],"relativePath":"zh-CN/contribute/index.md","filePath":"zh-CN/contribute/index.md"}'),t={name:"zh-CN/contribute/index.md"},a=i('<h1 id="关于-pr-pull-request" tabindex="-1">关于 PR (Pull Request) <a class="header-anchor" href="#关于-pr-pull-request" aria-label="Permalink to &quot;关于 PR (Pull Request)&quot;">​</a></h1><ol><li>前提: 你应该先阅读 <a href="./../completion/">关于补全的 json 文件结构</a></li><li>你应该 fork <a href="https://github.com/abgox/PSCompletions" target="_blank" rel="noreferrer">PSCompletions 仓库</a>，克隆到本地进行修改</li><li>只要到补全文件进行了修改，都需要更新其目录下的 <code>guid.txt</code> 文件 <ul><li>你可以手动运行 <code>New-Guid</code> 生成，将值填入此文件中</li><li>也可以直接运行 <code>.\\script\\updateGuid.ps1</code>，在弹出的 PowerShell 列表框中，选择此补全，并应用修改即可</li></ul></li><li>修改完成后，提交并创建 <code>PR</code></li></ol><h2 id="_1-更新-json-文件内容" tabindex="-1">1. 更新 json 文件内容 <a class="header-anchor" href="#_1-更新-json-文件内容" aria-label="Permalink to &quot;1. 更新 json 文件内容&quot;">​</a></h2><ul><li>完善补全的一些提示信息(<code>tip</code> 属性)</li><li>添加补全的一些缺失的命令</li></ul><h2 id="_2-添加语言" tabindex="-1">2. 添加语言 <a class="header-anchor" href="#_2-添加语言" aria-label="Permalink to &quot;2. 添加语言&quot;">​</a></h2><ol><li>在项目的 <code>completions</code> 目录中找到你想要添加语言的补全</li><li>在其目录下的 <code>config.json</code> 文件中的 <code>language</code> 属性里添加像 <code>zh-CN</code> 这样的语言标识符</li><li>在 <code>language</code> 目录下添加与语言标识符同名的 json 文件 <ul><li>你可以将原有的一个 json 文件直接复制，改名即可</li></ul></li><li>翻译其中的 <code>tip</code> 属性的内容即可</li></ol><h2 id="_3-添加一个全新的命令补全" tabindex="-1">3. 添加一个全新的命令补全 <a class="header-anchor" href="#_3-添加一个全新的命令补全" aria-label="Permalink to &quot;3. 添加一个全新的命令补全&quot;">​</a></h2><ol><li>在项目根目录下运行 <code>.\\script\\create.ps1</code></li><li>根据提示进行操作</li><li>修改新创建的补全</li><li>最后还需要在项目根目录的 <code>completions.json</code> 中的 <code>list</code> 属性值中添加此补全</li></ol>',8),c=[a];function d(n,r,s,u,h,_){return l(),o("div",null,c)}const P=e(t,[["render",d]]);export{m as __pageData,P as default};
